import { useState, useRef } from 'react';
import { toast } from 'sonner';
import { read, utils } from 'xlsx';
import { UploadCloud, FileType2, Loader2, AlertCircle } from 'lucide-react';
import { Button } from '@/components/ui/button';
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
    DialogFooter,
} from '@/components/ui/dialog';
import { useClientes } from '@/hooks/useClientes';

interface Props {
    open: boolean;
    onOpenChange: (open: boolean) => void;
}

export function ClienteBulkImportDialog({ open, onOpenChange }: Props) {
    const { createCliente } = useClientes();
    const [file, setFile] = useState<File | null>(null);
    const [isUploading, setIsUploading] = useState(false);
    const [progress, setProgress] = useState(0);
    const [totalRows, setTotalRows] = useState(0);
    const [errors, setErrors] = useState<string[]>([]);

    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files.length > 0) {
            setFile(e.target.files[0]);
            setErrors([]);
            setProgress(0);
            setTotalRows(0);
        }
    };

    const processImport = async () => {
        if (!file) {
            toast.error("Por favor selecciona un archivo.");
            return;
        }

        setIsUploading(true);
        setErrors([]);
        setProgress(0);

        try {
            // Read file with xlsx
            const buffer = await file.arrayBuffer();
            const workbook = read(buffer, { type: 'array' });
            const firstSheetName = workbook.SheetNames[0];
            const worksheet = workbook.Sheets[firstSheetName];

            // Convert to JSON
            const data = utils.sheet_to_json<any>(worksheet);

            if (!data || data.length === 0) {
                toast.error("El archivo est├í vac├¡o o no se pudo leer.");
                setIsUploading(false);
                return;
            }

            setTotalRows(data.length);
            let currentProgress = 0;
            const newErrors: string[] = [];

            // Process row by row
            for (let i = 0; i < data.length; i++) {
                const row = data[i];

                try {
                    const razon_social = row['Razon Social'] || row.razon_social || row['RAZON SOCIAL'] || row.Nombre || row.nombre || '';
                    if (!razon_social) throw new Error(`Fila ${i + 2}: No tiene Raz├│n Social o Nombre.`);

                    const rut = String(row.RUT || row.rut || row.Rut || row.Cedula || row.cedula || '000000000000');
                    const nombre_fantasia = row['Nombre Fantasia'] || row.nombre_fantasia || row['FANTASIA'] || row.Fantasia || '';
                    const direccion = row.Direccion || row.direccion || row.DIRECCION || row['Direcci├│n'] || '-';
                    const contacto_principal = row.Contacto || row.contacto || row.CONTACTO || '';
                    const telefono = String(row.Telefono || row.telefono || row.TELEFONO || row['Tel├®fono'] || '');
                    const email = row.Email || row.email || row.EMAIL || '';

                    await createCliente.mutateAsync({
                        razon_social,
                        nombre_fantasia,
                        rut,
                        direccion,
                        telefono,
                        email,
                        contacto_principal,
                        estado: 'activo'
                    });

                } catch (err /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */) {
                    newErrors.push(err.message || `Fila ${i + 2}: Error desconocido al procesar cliente`);
                }

                currentProgress++;
                setProgress(currentProgress);
            }

            setErrors(newErrors);

            if (newErrors.length === 0) {
                toast.success(`Se han importado ${data.length} clientes correctamente.`);
                setTimeout(() => {
                    onOpenChange(false);
                    setFile(null);
                }, 1500);
            } else {
                toast.warning(`Importaci├│n completada con ${newErrors.length} errores.`);
            }

        } catch (error) {
            console.error(error);
            toast.error("Ocurri├│ un error general leyendo el archivo.");
        } finally {
            setIsUploading(false);
        }
    };

    return (
        <Dialog open={open} onOpenChange={(val) => !isUploading && onOpenChange(val)}>
            <DialogContent className="sm:max-w-md">
                <DialogHeader>
                    <DialogTitle>Importaci├│n Masiva de Clientes</DialogTitle>
                    <DialogDescription>
                        Sube un archivo de Google Sheets o Excel para registrar clientes en lote. Columnas recomendadas: Raz├│n Social, RUT, Direcci├│n, Fantasia, Contacto, Tel├®fono, Email.
                    </DialogDescription>
                </DialogHeader>

                <div className="flex flex-col items-center justify-center p-6 border-2 border-dashed border-slate-300 dark:border-slate-700 rounded-xl bg-slate-50 dark:bg-slate-900/50 mt-4 transition-colors hover:bg-slate-100 dark:hover:bg-slate-800/50">
                    <input
                        type="file"
                        accept=".xlsx, .xls, .csv"
                        className="hidden"
                        ref={fileInputRef}
                        onChange={handleFileChange}
                        disabled={isUploading}
                    />

                    {file ? (
                        <div className="flex flex-col items-center text-center space-y-2">
                            <FileType2 className="h-10 w-10 text-coreops-primary" />
                            <p className="text-sm font-semibold">{file.name}</p>
                            <p className="text-xs text-slate-500">{(file.size / 1024).toFixed(1)} KB</p>
                            {!isUploading && (
                                <Button variant="link" size="sm" onClick={() => setFile(null)} className="text-red-500 h-auto p-0">Quitar archivo</Button>
                            )}
                        </div>
                    ) : (
                        <div
                            className="flex flex-col items-center text-center space-y-2 cursor-pointer"
                            onClick={() => fileInputRef.current?.click()}
                        >
                            <div className="p-3 bg-blue-100 dark:bg-blue-900/50 text-coreops-primary dark:text-blue-400 rounded-full">
                                <UploadCloud className="h-8 w-8" />
                            </div>
                            <p className="text-sm font-medium">Click para seleccionar archivo</p>
                            <p className="text-xs text-slate-500">Formato Soportado: .xlsx, .csv</p>
                        </div>
                    )}
                </div>

                {/* Progress Indicators */}
                {isUploading && (
                    <div className="mt-4 space-y-2">
                        <div className="flex justify-between text-xs font-semibold">
                            <span>Importando...</span>
                            <span>{progress} / {totalRows}</span>
                        </div>
                        <div className="w-full bg-slate-200 dark:bg-slate-800 rounded-full h-2.5">
                            <div className="bg-coreops-primary h-2.5 rounded-full transition-all duration-300" style={{ width: `${totalRows > 0 ? (progress / totalRows) * 100 : 0}%` }}></div>
                        </div>
                    </div>
                )}

                {/* Error Box */}
                {!isUploading && errors.length > 0 && (
                    <div className="mt-4 p-3 bg-red-50 border border-red-200 text-red-700 text-xs rounded-md max-h-32 overflow-y-auto w-full">
                        <div className="flex items-center font-bold mb-1">
                            <AlertCircle className="h-4 w-4 mr-1" /> Ocurrieron Errores:
                        </div>
                        <ul className="list-disc pl-5 space-y-1">
                            {errors.map((e, idx) => <li key={idx}>{e}</li>)}
                        </ul>
                    </div>
                )}

                <DialogFooter className="mt-6 flex gap-2 sm:justify-between">
                    <Button variant="outline" onClick={() => onOpenChange(false)} disabled={isUploading}>
                        Cancelar
                    </Button>
                    <Button onClick={processImport} disabled={!file || isUploading} className="min-w-[120px]">
                        {isUploading ? <><Loader2 className="h-4 w-4 mr-2 animate-spin" /> Procesando</> : 'Comenzar Importaci├│n'}
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

import { useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog';
import {
    Form,
    FormControl,
    FormField,
    FormItem,
    FormLabel,
    FormMessage,
} from '@/components/ui/form';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import type { ClienteFormData } from '@/lib/validations/cliente';
import { clienteSchema } from '@/lib/validations/cliente';
import { useClientes } from '@/hooks/useClientes';

interface Props {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    clienteToEdit? /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */ | null; // usually Cliente type
}

export function ClienteFormDialog({ open, onOpenChange, clienteToEdit }: Props) {
    const { createCliente, updateCliente } = useClientes();

    const form = useForm<ClienteFormData>({
        resolver: zodResolver(clienteSchema)  /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */,
        defaultValues: {
            razon_social: '',
            nombre_fantasia: '',
            rut: '',
            direccion: '',
            telefono: '',
            email: '',
            contacto_principal: '',
            frecuencia_visita: '',
            carga_horaria: '',
            estado: 'activo',
        },
    });

    useEffect(() => {
        if (clienteToEdit) {
            form.reset({
                id: clienteToEdit.id,
                razon_social: clienteToEdit.razon_social || '',
                nombre_fantasia: clienteToEdit.nombre_fantasia || '',
                rut: clienteToEdit.rut || '',
                direccion: clienteToEdit.direccion || '',
                telefono: clienteToEdit.telefono || '',
                email: clienteToEdit.email || '',
                contacto_principal: clienteToEdit.contacto_principal || '',
                frecuencia_visita: clienteToEdit.frecuencia_visita || '',
                carga_horaria: clienteToEdit.carga_horaria || '',
                estado: clienteToEdit.estado  /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */ || 'activo',
            });
        } else {
            form.reset({
                razon_social: '',
                nombre_fantasia: '',
                rut: '',
                direccion: '',
                telefono: '',
                email: '',
                contacto_principal: '',
                frecuencia_visita: '',
                carga_horaria: '',
                estado: 'activo',
            });
        }
    }, [clienteToEdit, form, open]);

    const onSubmit = async (data: ClienteFormData) => {
        const isEditing = !!clienteToEdit;
        const loadingId = toast.loading(isEditing ? 'Actualizando cliente...' : 'Registrando cliente...');

        try {
            if (isEditing) {
                await updateCliente.mutateAsync({ id: clienteToEdit!.id, data });
                toast.dismiss(loadingId);
                toast.success('Cliente actualizado correctamente');
            } else {
                await createCliente.mutateAsync(data);
                toast.dismiss(loadingId);
                toast.success('Cliente registrado exitosamente');
            }
            onOpenChange(false);
        } catch (error /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */) {
            console.error("Form Submit Error:", error);
            toast.dismiss(loadingId);
            toast.error(`Error al revisar datos: ${error.message || 'No se pudo guardar la informaci├│n'}`, { duration: 8000 });
        }
    };

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="sm:max-w-[700px] max-h-[90vh] overflow-y-auto">
                <DialogHeader>
                    <DialogTitle>{clienteToEdit ? 'Editar Cliente' : 'A├▒adir Nuevo Cliente (Empresa o Persona)'}</DialogTitle>
                </DialogHeader>

                <Form {...form}>
                    <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
                        <div className="grid grid-cols-2 gap-4">

                            <div className="space-y-2 col-span-2">
                                <h3 className="font-semibold border-b pb-2">Informaci├│n Fiscal o Personal</h3>
                            </div>

                            <FormField
                                control={form.control}
                                name="razon_social"
                                render={({ field }) => (
                                    <FormItem className="col-span-2 sm:col-span-1">
                                        <FormLabel>Raz├│n Social / Nombre (Obligatorio)</FormLabel>
                                        <FormControl>
                                            <Input placeholder="Ej. Empresa SA o Juan L├│pez" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <FormField
                                control={form.control}
                                name="nombre_fantasia"
                                render={({ field }) => (
                                    <FormItem className="col-span-2 sm:col-span-1">
                                        <FormLabel>Nombre de Fantas├¡a (Opcional)</FormLabel>
                                        <FormControl>
                                            <Input placeholder="Ej. Tienda Centro" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <FormField
                                control={form.control}
                                name="rut"
                                render={({ field }) => (
                                    <FormItem className="col-span-2 sm:col-span-1">
                                        <FormLabel>RUT / C├®dula</FormLabel>
                                        <FormControl>
                                            <Input placeholder="Ej. 210000.. o 1234567" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <FormField
                                control={form.control}
                                name="estado"
                                render={({ field }) => (
                                    <FormItem className="col-span-2 sm:col-span-1">
                                        <FormLabel>Estado</FormLabel>
                                        <Select onValueChange={field.onChange} defaultValue={field.value}>
                                            <FormControl>
                                                <SelectTrigger>
                                                    <SelectValue placeholder="Seleccionar estado" />
                                                </SelectTrigger>
                                            </FormControl>
                                            <SelectContent>
                                                <SelectItem value="activo">Activo</SelectItem>
                                                <SelectItem value="inactivo">Inactivo</SelectItem>
                                            </SelectContent>
                                        </Select>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <div className="space-y-2 col-span-2 mt-4">
                                <h3 className="font-semibold border-b pb-2">Acuerdo de Servicio Operativo</h3>
                            </div>

                            <FormField
                                control={form.control}
                                name="frecuencia_visita"
                                render={({ field }) => (
                                    <FormItem className="col-span-2 sm:col-span-1">
                                        <FormLabel>Per├¡odo de Asistencia</FormLabel>
                                        <Select onValueChange={field.onChange} defaultValue={field.value || undefined} value={field.value || undefined}>
                                            <FormControl>
                                                <SelectTrigger>
                                                    <SelectValue placeholder="Seleccionar per├¡odo" />
                                                </SelectTrigger>
                                            </FormControl>
                                            <SelectContent>
                                                <SelectItem value="diaria">Diaria</SelectItem>
                                                <SelectItem value="semanal">Semanal</SelectItem>
                                                <SelectItem value="quincenal">Quincenal</SelectItem>
                                                <SelectItem value="anual">Anual</SelectItem>
                                            </SelectContent>
                                        </Select>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <FormField
                                control={form.control}
                                name="carga_horaria"
                                render={({ field }) => (
                                    <FormItem className="col-span-2 sm:col-span-1">
                                        <FormLabel>Carga Horaria / Franja</FormLabel>
                                        <FormControl>
                                            <Input placeholder="Ej. 00:00 a 08:00 hs" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <div className="space-y-2 col-span-2 mt-4">
                                <h3 className="font-semibold border-b pb-2">Contacto y Ubicaci├│n</h3>
                            </div>

                            <FormField
                                control={form.control}
                                name="direccion"
                                render={({ field }) => (
                                    <FormItem className="col-span-2">
                                        <FormLabel>Direcci├│n Principal (Oficinas)</FormLabel>
                                        <FormControl>
                                            <Input placeholder="Ej. Av. Siempreviva 742" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <FormField
                                control={form.control}
                                name="contacto_principal"
                                render={({ field }) => (
                                    <FormItem className="col-span-2 sm:col-span-1">
                                        <FormLabel>Persona de Contacto</FormLabel>
                                        <FormControl>
                                            <Input placeholder="Ej. Mar├¡a L├│pez" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <FormField
                                control={form.control}
                                name="telefono"
                                render={({ field }) => (
                                    <FormItem className="col-span-2 sm:col-span-1">
                                        <FormLabel>Tel├®fono</FormLabel>
                                        <FormControl>
                                            <Input placeholder="Ej. 091234567" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <FormField
                                control={form.control}
                                name="email"
                                render={({ field }) => (
                                    <FormItem className="col-span-2">
                                        <FormLabel>Correo Electr├│nico (Para facturaci├│n/comunicaci├│n)</FormLabel>
                                        <FormControl>
                                            <Input type="email" placeholder="contacto@empresa.com" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                        </div>

                        <div className="flex justify-end pt-6 border-t mt-4 gap-2">
                            <Button type="button" variant="outline" onClick={() => onOpenChange(false)}>
                                Cancelar
                            </Button>
                            <Button type="submit">
                                {clienteToEdit ? 'Actualizar Cliente' : 'Guardar Cliente'}
                            </Button>
                        </div>
                    </form>
                </Form>
            </DialogContent>
        </Dialog>
    );
}

import { useState, useRef } from 'react';
import { toast } from 'sonner';
import { read, utils } from 'xlsx';
import { UploadCloud, FileType2, Loader2, AlertCircle } from 'lucide-react';
import { Button } from '@/components/ui/button';
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
    DialogFooter,
} from '@/components/ui/dialog';
import { useFuncionarios } from '@/hooks/useFuncionarios';

interface Props {
    open: boolean;
    onOpenChange: (open: boolean) => void;
}

export function FuncionarioBulkImportDialog({ open, onOpenChange }: Props) {
    const { createFuncionario, getDepartamentos, createDepartamento } = useFuncionarios();
    const [file, setFile] = useState<File | null>(null);
    const [isUploading, setIsUploading] = useState(false);
    const [progress, setProgress] = useState(0);
    const [totalRows, setTotalRows] = useState(0);
    const [errors, setErrors] = useState<string[]>([]);

    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files.length > 0) {
            setFile(e.target.files[0]);
            setErrors([]);
            setProgress(0);
            setTotalRows(0);
        }
    };

    const processImport = async () => {
        if (!file) {
            toast.error("Por favor selecciona un archivo.");
            return;
        }

        setIsUploading(true);
        setErrors([]);
        setProgress(0);

        try {
            // Read file with exceljs / xlsx
            const buffer = await file.arrayBuffer();
            const workbook = read(buffer, { type: 'array', cellDates: true });
            const firstSheetName = workbook.SheetNames[0];
            const worksheet = workbook.Sheets[firstSheetName];

            // Convert to JSON
            const data = utils.sheet_to_json<any>(worksheet);

            if (!data || data.length === 0) {
                toast.error("El archivo est├í vac├¡o o no se pudo leer.");
                setIsUploading(false);
                return;
            }

            setTotalRows(data.length);

            // Fetch current departments to match IDs
            const currentDeptos = getDepartamentos.data || [];

            let currentProgress = 0;
            const newErrors: string[] = [];

            // Process row by row
            for (let i = 0; i < data.length; i++) {
                const row = data[i];

                try {
                    // Try mapping columns (expected headers)
                    const emailRaw = row.Email || row.email || row.EMAIL || row.Correo || '';
                    const email = emailRaw ? emailRaw.toString().trim() : '';

                    const nombre = row.Nombre || row.nombre || row.NOMBRE || '-';
                    const apellido = row.Apellido || row.apellido || row.APELLIDO || '-';
                    const cedula = String(row.Cedula || row.cedula || row.CEDULA || '0000000');
                    const cargo = row.Cargo || row.cargo || row.CARGO || 'General';
                    const direccion = row.Direcci├│n || row.direccion || row.DIRECCION || row.Direccion || '-';

                    // Match department by name vaguely, by exact ID, or safely fallback to first one
                    const reqDeptoId = row.departamento_id || row.Departamento_id;
                    const reqDeptoNameOriginal = String(row.Departamento || row.departamento || row.DEPARTAMENTO || 'General').trim();
                    const reqDeptoName = reqDeptoNameOriginal.toLowerCase();

                    let matchedDepto = reqDeptoId
                        ? currentDeptos.find(d => d.id === reqDeptoId)
                        : currentDeptos.find(d => d.nombre.toLowerCase() === reqDeptoName);

                    if (!matchedDepto) {
                        try {
                            matchedDepto = await createDepartamento.mutateAsync(reqDeptoNameOriginal);
                            if (matchedDepto) currentDeptos.push(matchedDepto);
                        } catch (e /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */) {
                            if (currentDeptos.length > 0) {
                                matchedDepto = currentDeptos[0]; // fallback
                            } else {
                                throw new Error(`Fila ${i + 2}: No hay departamentos y error al crear '${reqDeptoNameOriginal}': ${e.message}`);
                            }
                        }
                    }

                    if (!matchedDepto) {
                        throw new Error(`Fila ${i + 2}: No hay departamentos creados en el sistema para asociar al empleado.`);
                    }

                    // Default role for bulk or grab from excel
                    const rol = (row.rol || row.Rol || row.ROL || 'funcionario').toLowerCase();
                    const password = row.password || row.Password || row.PASSWORD || cedula; // Default password is the ID

                    let parsedFechaIngreso = new Date().toISOString().split('T')[0];
                    const rawFecha = row.fecha_ingreso || row.Fecha_ingreso || row.Fecha_Ingreso || row.FECHA_INGRESO || row.Ingreso || row.ingreso;

                    if (rawFecha instanceof Date) {
                        // Extract correctly ignoring timezone shifts in the Date output
                        const d = new Date(rawFecha);
                        parsedFechaIngreso = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
                    } else if (typeof rawFecha === 'number') {
                        // Fallback: Convert Excel Serial Date to JS Date
                        const jsDate = new Date(Math.round((rawFecha - 25569) * 86400 * 1000));
                        parsedFechaIngreso = jsDate.toISOString().split('T')[0];
                    } else if (typeof rawFecha === 'string' && rawFecha.trim() !== '') {
                        // Try to fix DD/MM/YYYY string formats to YYYY-MM-DD for PostgreSQL
                        let parts = rawFecha.includes('/') ? rawFecha.split('/') : rawFecha.split('-');
                        if (parts.length === 3) {
                            // Find the 4-digit year format
                            const yearIndex = parts.findIndex(p => p.length === 4);
                            if (yearIndex === 2) {
                                // XX/XX/YYYY
                                const p0 = parseInt(parts[0], 10);
                                const p1 = parseInt(parts[1], 10);
                                if (p1 > 12) {
                                    // p1 is day, p0 is month -> MM/DD/YYYY
                                    parsedFechaIngreso = `${parts[2]}-${String(p0).padStart(2, '0')}-${String(p1).padStart(2, '0')}`;
                                } else {
                                    // default to DD/MM/YYYY format
                                    parsedFechaIngreso = `${parts[2]}-${String(p1).padStart(2, '0')}-${String(p0).padStart(2, '0')}`;
                                }
                            } else if (yearIndex === 0) {
                                // YYYY/MM/DD
                                parsedFechaIngreso = `${parts[0]}-${String(parts[1]).padStart(2, '0')}-${String(parts[2]).padStart(2, '0')}`;
                            } else {
                                parsedFechaIngreso = rawFecha.split('/').reverse().join('-');
                            }
                        } else {
                            parsedFechaIngreso = rawFecha.includes('/') ? rawFecha.split('/').reverse().join('-') : rawFecha;
                        }
                    }

                    const fecha_ingreso = parsedFechaIngreso;
                    const tipo_contrato = row.tipo_contrato || row.Tipo_contrato || 'Indefinido';
                    const estado = (row.estado || row.Estado || 'activo').toLowerCase();

                    await createFuncionario.mutateAsync({
                        nombre,
                        apellido,
                        email,
                        password,
                        rol,
                        cedula,
                        cargo,
                        departamento_id: matchedDepto.id,
                        direccion,
                        fecha_ingreso,
                        tipo_contrato,
                        estado
                    });

                } catch (err /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */) {
                    const msg = err.message || '';
                    if (msg.includes('duplicate key value') || msg.includes('cedula_key')) {
                        const duplicateCedula = row.Cedula || row.cedula || row.CEDULA || 'especificada';
                        newErrors.push(`Fila ${i + 2}: El funcionario con la c├®dula ${duplicateCedula} ya se encuentra registrado.`);
                    } else if (msg.includes('date/time field value out of range')) {
                        newErrors.push(`Fila ${i + 2}: El formato de la fecha de ingreso es inv├ílido o incomprensible.`);
                    } else {
                        newErrors.push(msg || `Fila ${i + 2}: Error desconocido`);
                    }
                }

                currentProgress++;
                setProgress(currentProgress);
            }

            setErrors(newErrors);

            if (newErrors.length === 0) {
                toast.success(`Se han importado ${data.length} funcionarios correctamente.`);
                setTimeout(() => {
                    onOpenChange(false);
                    setFile(null);
                }, 1500);
            } else {
                toast.warning(`Importaci├│n completada con ${newErrors.length} errores.`);
            }

        } catch (error) {
            console.error(error);
            toast.error("Ocurri├│ un error general leyendo el archivo.");
        } finally {
            setIsUploading(false);
        }
    };

    return (
        <Dialog open={open} onOpenChange={(val) => !isUploading && onOpenChange(val)}>
            <DialogContent className="sm:max-w-md">
                <DialogHeader>
                    <DialogTitle>Importaci├│n Masiva (Excel/CSV)</DialogTitle>
                    <DialogDescription>
                        Sube un archivo de Google Sheets o Excel para registrar personal en lote. Las columnas esperadas son: Nombre, Apellido, Cedula, Cargo, Departamento, Direccion. (Email es Opcional).
                    </DialogDescription>
                </DialogHeader>

                <div className="flex flex-col items-center justify-center p-6 border-2 border-dashed border-slate-300 dark:border-slate-700 rounded-xl bg-slate-50 dark:bg-slate-900/50 mt-4 transition-colors hover:bg-slate-100 dark:hover:bg-slate-800/50">
                    <input
                        type="file"
                        accept=".xlsx, .xls, .csv"
                        className="hidden"
                        ref={fileInputRef}
                        onChange={handleFileChange}
                        disabled={isUploading}
                    />

                    {file ? (
                        <div className="flex flex-col items-center text-center space-y-2">
                            <FileType2 className="h-10 w-10 text-coreops-primary" />
                            <p className="text-sm font-semibold">{file.name}</p>
                            <p className="text-xs text-slate-500">{(file.size / 1024).toFixed(1)} KB</p>
                            {!isUploading && (
                                <Button variant="link" size="sm" onClick={() => setFile(null)} className="text-red-500 h-auto p-0">Quitar archivo</Button>
                            )}
                        </div>
                    ) : (
                        <div
                            className="flex flex-col items-center text-center space-y-2 cursor-pointer"
                            onClick={() => fileInputRef.current?.click()}
                        >
                            <div className="p-3 bg-blue-100 dark:bg-blue-900/50 text-coreops-primary dark:text-blue-400 rounded-full">
                                <UploadCloud className="h-8 w-8" />
                            </div>
                            <p className="text-sm font-medium">Click para seleccionar archivo</p>
                            <p className="text-xs text-slate-500">Formato Soportado: .xlsx, .csv</p>
                        </div>
                    )}
                </div>

                {/* Progress Indicators */}
                {isUploading && (
                    <div className="mt-4 space-y-2">
                        <div className="flex justify-between text-xs font-semibold">
                            <span>Importando...</span>
                            <span>{progress} / {totalRows}</span>
                        </div>
                        <div className="w-full bg-slate-200 dark:bg-slate-800 rounded-full h-2.5">
                            <div className="bg-coreops-primary h-2.5 rounded-full transition-all duration-300" style={{ width: `${totalRows > 0 ? (progress / totalRows) * 100 : 0}%` }}></div>
                        </div>
                    </div>
                )}

                {/* Error Box */}
                {!isUploading && errors.length > 0 && (
                    <div className="mt-4 p-3 bg-red-50 border border-red-200 text-red-700 text-xs rounded-md max-h-32 overflow-y-auto w-full">
                        <div className="flex items-center font-bold mb-1">
                            <AlertCircle className="h-4 w-4 mr-1" /> Ocurrieron Errores:
                        </div>
                        <ul className="list-disc pl-5 space-y-1">
                            {errors.map((e, idx) => <li key={idx}>{e}</li>)}
                        </ul>
                    </div>
                )}

                <DialogFooter className="mt-6 flex gap-2 sm:justify-between">
                    <Button variant="outline" onClick={() => onOpenChange(false)} disabled={isUploading}>
                        Cancelar
                    </Button>
                    <Button onClick={processImport} disabled={!file || isUploading} className="min-w-[120px]">
                        {isUploading ? <><Loader2 className="h-4 w-4 mr-2 animate-spin" /> Procesando</> : 'Comenzar Importaci├│n'}
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

import { useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog';
import {
    Form,
    FormControl,
    FormField,
    FormItem,
    FormLabel,
    FormMessage,
} from '@/components/ui/form';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import type { FuncionarioFormData } from '@/lib/validations/funcionario';
import { funcionarioSchema } from '@/lib/validations/funcionario';
import { useFuncionarios } from '@/hooks/useFuncionarios';

interface Props {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    funcionarioToEdit? /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */ | null; // using any for simplicity, usually Funcionario type
}

export function FuncionarioFormDialog({ open, onOpenChange, funcionarioToEdit }: Props) {
    const { getDepartamentos, createDepartamento, createFuncionario, updateFuncionario } = useFuncionarios();
    const form = useForm<FuncionarioFormData>({
        resolver: zodResolver(funcionarioSchema)  /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */,
        defaultValues: {
            nombre: '',
            apellido: '',
            email: '',
            password: '',
            rol: 'funcionario',
            cedula: '',
            cargo: '',
            departamento_id: '',
            direccion: '',
            fecha_ingreso: new Date().toISOString().split('T')[0],
            tipo_contrato: '',
            estado: 'activo',
        },
    });

    useEffect(() => {
        if (funcionarioToEdit) {
            form.reset({
                id: funcionarioToEdit.id,
                nombre: funcionarioToEdit.profiles?.nombre || '',
                apellido: funcionarioToEdit.profiles?.apellido || '',
                email: funcionarioToEdit.profiles?.email || '',
                password: '', // do not set password on edit
                rol: (funcionarioToEdit.profiles?.rol  /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */) || 'funcionario',
                cedula: funcionarioToEdit.cedula,
                cargo: funcionarioToEdit.cargo,
                departamento_id: funcionarioToEdit.departamento_id || '',
                direccion: funcionarioToEdit.direccion || '',
                fecha_ingreso: funcionarioToEdit.fecha_ingreso,
                tipo_contrato: funcionarioToEdit.tipo_contrato,
                estado: funcionarioToEdit.estado  /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */,
            });
        } else {
            form.reset();
        }
    }, [funcionarioToEdit, form]);

    const onSubmit = async (data: FuncionarioFormData) => {
        const isEditing = !!funcionarioToEdit;
        const loadingId = toast.loading(isEditing ? 'Actualizando funcionario...' : 'Validando datos...');

        try {
            // Let the mutation handle its own timeout if we want, or do it here
            const timeoutPromise = new Promise((_, reject) => setTimeout(() => reject(new Error('Tiempo de espera agotado en Supabase al procesar.')), 20000));
            
            if (isEditing) {
                await Promise.race([updateFuncionario.mutateAsync({ id: funcionarioToEdit!.id, data }), timeoutPromise]);
                toast.success('Funcionario actualizado correctamente', { id: loadingId });
            } else {
                toast.loading('Iniciando guardado remoto...', { id: loadingId });
                await Promise.race([createFuncionario.mutateAsync(data), timeoutPromise]);
                // the mutation itself shows a success toast for "5/5" and hides "Iniciando guardado remoto..."
            }
            onOpenChange(false);
        } catch (error /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */) {
            console.error("Form Submit Error:", error);
            const msg = error.message || 'No se pudo guardar la informaci├│n';
            toast.error(`Error: ${msg}`, { id: loadingId, duration: 10000 });
        }
    };

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="sm:max-w-[700px] max-h-[90vh] overflow-y-auto">
                <DialogHeader>
                    <DialogTitle>{funcionarioToEdit ? 'Editar Funcionario' : 'A├▒adir Nuevo Funcionario'}</DialogTitle>
                </DialogHeader>

                <Form {...form}>
                    <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">

                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2 col-span-2">
                                <h3 className="font-semibold border-b pb-2">Datos de Perfil (Acceso)</h3>
                            </div>
                            <FormField
                                control={form.control}
                                name="nombre"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel>Nombre</FormLabel>
                                        <FormControl>
                                            <Input placeholder="Ej. Juan" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />
                            <FormField
                                control={form.control}
                                name="apellido"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel>Apellido</FormLabel>
                                        <FormControl>
                                            <Input placeholder="Ej. P├®rez" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />
                            <FormField
                                control={form.control}
                                name="email"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel>Correo Electr├│nico (Opcional)</FormLabel>
                                        <FormControl>
                                            <Input type="email" placeholder="usuario@empresa.com" disabled={!!funcionarioToEdit} {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            {!funcionarioToEdit && (
                                <FormField
                                    control={form.control}
                                    name="password"
                                    render={({ field }) => (
                                        <FormItem>
                                            <FormLabel>Contrase├▒a Inicial (Opcional)</FormLabel>
                                            <FormControl>
                                                <Input type="password" placeholder="Autogenerada si se omite..." {...field} />
                                            </FormControl>
                                            <FormMessage />
                                        </FormItem>
                                    )}
                                />
                            )}

                            <FormField
                                control={form.control}
                                name="rol"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel>Rol de Sistema</FormLabel>
                                        <Select onValueChange={field.onChange} defaultValue={field.value}>
                                            <FormControl>
                                                <SelectTrigger>
                                                    <SelectValue placeholder="Seleccionar rol" />
                                                </SelectTrigger>
                                            </FormControl>
                                            <SelectContent>
                                                <SelectItem value="funcionario">Funcionario</SelectItem>
                                                <SelectItem value="supervisor">Supervisor</SelectItem>
                                                <SelectItem value="admin">Administrador</SelectItem>
                                                <SelectItem value="facturador">Facturador</SelectItem>
                                                <SelectItem value="superadmin">Super Admin</SelectItem>
                                            </SelectContent>
                                        </Select>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <div className="space-y-2 col-span-2 mt-4">
                                <h3 className="font-semibold border-b pb-2">Datos Laborales</h3>
                            </div>

                            <FormField
                                control={form.control}
                                name="cedula"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel>C├®dula / DNI</FormLabel>
                                        <FormControl>
                                            <Input placeholder="12345678" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />
                            <FormField
                                control={form.control}
                                name="cargo"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel>Cargo</FormLabel>
                                        <FormControl>
                                            <Input placeholder="Ej. Encargado de Limpieza" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <FormField
                                control={form.control}
                                name="tipo_contrato"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel>Tipo de Contrato</FormLabel>
                                        <Select onValueChange={field.onChange} defaultValue={field.value}>
                                            <FormControl>
                                                <SelectTrigger>
                                                    <SelectValue placeholder="Seleccionar tipo" />
                                                </SelectTrigger>
                                            </FormControl>
                                            <SelectContent>
                                                <SelectItem value="indefinido">Indefinido</SelectItem>
                                                <SelectItem value="zafral">Zafral</SelectItem>
                                                <SelectItem value="jornalero">Jornalero</SelectItem>
                                                <SelectItem value="a_prueba">A prueba</SelectItem>
                                            </SelectContent>
                                        </Select>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <FormField
                                control={form.control}
                                name="departamento_id"
                                render={({ field }) => (
                                    <FormItem>
                                        <div className="flex items-center justify-between">
                                            <FormLabel>Departamento</FormLabel>
                                            <Button
                                                type="button"
                                                variant="ghost"
                                                size="sm"
                                                className="h-6 px-2 text-xs text-coreops-primary"
                                                onClick={async () => {
                                                    const name = window.prompt('Nombre del nuevo departamento:');
                                                    if (name) {
                                                        const promise = createDepartamento.mutateAsync(name);
                                                        toast.promise(promise, {
                                                            loading: 'Creando...',
                                                            success: (data) => {
                                                                form.setValue('departamento_id', data.id);
                                                                return 'Departamento a├▒adido';
                                                            },
                                                            error: (err /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */) => `Error al crear: ${err.message}`
                                                        });
                                                    }
                                                }}
                                            >
                                                + A├▒adir
                                            </Button>
                                        </div>
                                        <Select onValueChange={field.onChange} value={field.value || undefined}>
                                            <FormControl>
                                                <SelectTrigger>
                                                    <SelectValue placeholder="Seleccionar depto" />
                                                </SelectTrigger>
                                            </FormControl>
                                            <SelectContent>
                                                {getDepartamentos.data && getDepartamentos.data.map(depto => (
                                                    <SelectItem key={depto.id} value={depto.id}>{depto.nombre}</SelectItem>
                                                ))}
                                                {getDepartamentos.data?.length === 0 && (
                                                    <SelectItem value="none" disabled>No hay departamentos</SelectItem>
                                                )}
                                            </SelectContent>
                                        </Select>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <FormField
                                control={form.control}
                                name="fecha_ingreso"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel>Fecha de Ingreso</FormLabel>
                                        <FormControl>
                                            <Input type="date" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <FormField
                                control={form.control}
                                name="direccion"
                                render={({ field }) => (
                                    <FormItem className="col-span-2">
                                        <FormLabel>Direcci├│n F├¡sica (Visible en mapa para log├¡stica)</FormLabel>
                                        <FormControl>
                                            <Input placeholder="Ej. Av. 18 de Julio 1234, Montevideo" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <FormField
                                control={form.control}
                                name="estado"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel>Estado</FormLabel>
                                        <Select onValueChange={field.onChange} defaultValue={field.value}>
                                            <FormControl>
                                                <SelectTrigger>
                                                    <SelectValue placeholder="Seleccionar estado" />
                                                </SelectTrigger>
                                            </FormControl>
                                            <SelectContent>
                                                <SelectItem value="activo">Activo</SelectItem>
                                                <SelectItem value="inactivo">Inactivo</SelectItem>
                                                <SelectItem value="vacaciones">Vacaciones</SelectItem>
                                                <SelectItem value="licencia">Licencia</SelectItem>
                                            </SelectContent>
                                        </Select>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                        </div>

                        <div className="flex justify-end pt-6 border-t mt-4 gap-2">
                            <Button type="button" variant="outline" onClick={() => onOpenChange(false)} disabled={form.formState.isSubmitting}>
                                Cancelar
                            </Button>
                            <Button type="submit" disabled={form.formState.isSubmitting}>
                                {form.formState.isSubmitting ? 'Guardando...' : (funcionarioToEdit ? 'Actualizar' : 'Guardar y Crear Acceso')}
                            </Button>
                        </div>
                    </form>
                </Form>
            </DialogContent>
        </Dialog>
    );
}

import { useState } from 'react';
import { Button } from '@/components/ui/button';
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogFooter,
    DialogDescription
} from '@/components/ui/dialog';
import { Checkbox } from '@/components/ui/checkbox';
import { Label } from '@/components/ui/label';
import { Printer } from 'lucide-react';

interface Props {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    employees /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */[];
}

export function FuncionarioPrintDialog({ open, onOpenChange, employees }: Props) {
    const [selectedColumns, setSelectedColumns] = useState({
        nombre: true,
        cedula: true,
        cargo: true,
        departamento: true,
        fecha_ingreso: false,
        direccion: false,
        estado: true,
        email: false
    });

    const handlePrint = () => {
        const printWindow = window.open('', '_blank');
        if (!printWindow) return;

        const dateStr = new Date().toLocaleDateString();

        const activeCount = employees.filter(e => e.estado === 'activo').length;
        const deptsCount = new Set(employees.map(e => e.departamentos?.nombre).filter(Boolean)).size;

        let tableHtml = `
      <html>
        <head>
          <title>Listado de Funcionarios</title>
          <style>
            body { font-family: sans-serif; padding: 20px; }
            table { width: 100%; border-collapse: collapse; margin-top: 20px; font-size: 14px; }
            th, td { border: 1px solid #ddd; padding: 8px; text-align: left; }
            th { background-color: #f2f2f2; }
            h2 { margin-bottom: 5px; }
            .summary { background-color: #f8f9fa; padding: 15px; border-radius: 5px; margin-bottom: 20px; border: 1px solid #e9ecef; }
            .summary ul { margin: 5px 0 0 0; padding-left: 20px; color: #444; font-size: 14px; }
            p { color: #555; font-size: 14px; margin: 0 0 10px 0; }
          </style>
        </head>
        <body>
          <h2>Reporte: Listado de Personal</h2>
          <div class="summary">
            <p><strong>Resumen del reporte emitido el ${dateStr}:</strong></p>
            <ul>
              <li><strong>Total de Funcionarios:</strong> ${employees.length}</li>
              <li><strong>Funcionarios Activos:</strong> ${activeCount}</li>
              <li><strong>Departamentos representados:</strong> ${deptsCount}</li>
            </ul>
          </div>
          <table>
            <thead>
              <tr>
                ${selectedColumns.nombre ? '<th>Nombre Completo</th>' : ''}
                ${selectedColumns.cedula ? '<th>C├®dula</th>' : ''}
                ${selectedColumns.cargo ? '<th>Cargo</th>' : ''}
                ${selectedColumns.departamento ? '<th>Departamento</th>' : ''}
                ${selectedColumns.fecha_ingreso ? '<th>F. Ingreso</th>' : ''}
                ${selectedColumns.direccion ? '<th>Direcci├│n</th>' : ''}
                ${selectedColumns.email ? '<th>Email</th>' : ''}
                ${selectedColumns.estado ? '<th>Estado</th>' : ''}
              </tr>
            </thead>
            <tbody>
        `;

        employees.forEach(emp => {
            const nombre = `${emp.profiles?.nombre || ''} ${emp.profiles?.apellido || ''}`;
            tableHtml += `
              <tr>
                ${selectedColumns.nombre ? `<td>${nombre}</td>` : ''}
                ${selectedColumns.cedula ? `<td>${emp.cedula || ''}</td>` : ''}
                ${selectedColumns.cargo ? `<td>${emp.cargo || ''}</td>` : ''}
                ${selectedColumns.departamento ? `<td>${emp.departamentos?.nombre || ''}</td>` : ''}
                ${selectedColumns.fecha_ingreso ? `<td>${emp.fecha_ingreso ? new Date(emp.fecha_ingreso).toLocaleDateString() : ''}</td>` : ''}
                ${selectedColumns.direccion ? `<td>${emp.direccion || ''}</td>` : ''}
                ${selectedColumns.email ? `<td>${emp.profiles?.email || ''}</td>` : ''}
                ${selectedColumns.estado ? `<td>${emp.estado || ''}</td>` : ''}
              </tr>
            `;
        });

        tableHtml += `
            </tbody>
          </table>
          <script>
            window.onload = function() { window.print(); window.close(); }
          </script>
        </body>
      </html>
    `;

        printWindow.document.write(tableHtml);
        printWindow.document.close();
        onOpenChange(false);
    };

    const toggleCol = (col: keyof typeof selectedColumns) => {
        setSelectedColumns(prev => ({ ...prev, [col]: !prev[col] }));
    };

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="sm:max-w-md">
                <DialogHeader>
                    <DialogTitle>Imprimir Listado</DialogTitle>
                    <DialogDescription>
                        Selecciona las columnas que deseas incluir en el reporte de impresi├│n para los {employees.length} funcionarios filtrados actualmente.
                    </DialogDescription>
                </DialogHeader>

                <div className="grid grid-cols-2 gap-4 py-4">
                    <div className="flex items-center space-x-2">
                        <Checkbox id="col_nombre" checked={selectedColumns.nombre} onCheckedChange={() => toggleCol('nombre')} />
                        <Label htmlFor="col_nombre">Nombre y Apellido</Label>
                    </div>
                    <div className="flex items-center space-x-2">
                        <Checkbox id="col_cedula" checked={selectedColumns.cedula} onCheckedChange={() => toggleCol('cedula')} />
                        <Label htmlFor="col_cedula">C├®dula</Label>
                    </div>
                    <div className="flex items-center space-x-2">
                        <Checkbox id="col_cargo" checked={selectedColumns.cargo} onCheckedChange={() => toggleCol('cargo')} />
                        <Label htmlFor="col_cargo">Cargo</Label>
                    </div>
                    <div className="flex items-center space-x-2">
                        <Checkbox id="col_departamento" checked={selectedColumns.departamento} onCheckedChange={() => toggleCol('departamento')} />
                        <Label htmlFor="col_departamento">Departamento</Label>
                    </div>
                    <div className="flex items-center space-x-2">
                        <Checkbox id="col_fecha_ingreso" checked={selectedColumns.fecha_ingreso} onCheckedChange={() => toggleCol('fecha_ingreso')} />
                        <Label htmlFor="col_fecha_ingreso">Fecha de Ingreso</Label>
                    </div>
                    <div className="flex items-center space-x-2">
                        <Checkbox id="col_direccion" checked={selectedColumns.direccion} onCheckedChange={() => toggleCol('direccion')} />
                        <Label htmlFor="col_direccion">Direcci├│n</Label>
                    </div>
                    <div className="flex items-center space-x-2">
                        <Checkbox id="col_email" checked={selectedColumns.email} onCheckedChange={() => toggleCol('email')} />
                        <Label htmlFor="col_email">Correo Electr├│nico</Label>
                    </div>
                    <div className="flex items-center space-x-2">
                        <Checkbox id="col_estado" checked={selectedColumns.estado} onCheckedChange={() => toggleCol('estado')} />
                        <Label htmlFor="col_estado">Estado</Label>
                    </div>
                </div>

                <DialogFooter className="mt-4">
                    <Button variant="outline" onClick={() => onOpenChange(false)}>Cancelar</Button>
                    <Button onClick={handlePrint}>
                        <Printer className="w-4 h-4 mr-2" /> Imprimir Documento
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

import { useState, useMemo } from 'react';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Search, Pencil, Printer, KeyRound, Stethoscope } from 'lucide-react';
import { FuncionarioPrintDialog } from './FuncionarioPrintDialog';

interface FuncionariosTableProps {
    employees /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */[];
    isLoading: boolean;
    onEdit: (funcionario /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */) => void;
    onResetPassword: (funcionario /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */) => void;
    onCertificaciones: (funcionario /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */) => void;
}

export function FuncionariosTable({ employees, isLoading, onEdit, onResetPassword, onCertificaciones }: FuncionariosTableProps) {
    const [searchTerm, setSearchTerm] = useState('');
    const [isPrintDialogOpen, setIsPrintDialogOpen] = useState(false);

    // Optimize array filtering by memoizing it to prevent recalculation on every render
    const filteredEmployees = useMemo(() => {
        return employees.filter((emp /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */) => {
            const search = searchTerm.toLowerCase();
            const n = emp?.profiles?.nombre?.toLowerCase() || '';
            const a = emp?.profiles?.apellido?.toLowerCase() || '';
            const cedula = emp?.cedula || '';
            const cargo = emp?.cargo?.toLowerCase() || '';
            return n.includes(search) || a.includes(search) || cedula.includes(search) || cargo.includes(search);
        });
    }, [employees, searchTerm]);

    // Pre-instantiate dateFormatter to avoid object allocation in .map()
    const dateFormatter = useMemo(() => new Intl.DateTimeFormat(undefined, {
        year: 'numeric',
        month: 'numeric',
        day: 'numeric'
    }), []);

    return (
        <Card className="border-slate-200 dark:border-slate-800 bg-white/60 dark:bg-slate-900/60 backdrop-blur-md shadow-sm">
            <CardHeader className="pb-4">
                <div className="flex flex-col sm:flex-row justify-between w-full items-center gap-4">
                    <CardTitle className="text-lg flex-1">Listado de Personal</CardTitle>
                    <div className="relative w-full sm:w-72">
                        <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                        <Input
                            placeholder="Buscar por nombre, CI o cargo..."
                            className="pl-9 bg-background/50 border-slate-200 dark:border-slate-700"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>
                    <Button
                        variant="outline"
                        onClick={() => setIsPrintDialogOpen(true)}
                        disabled={filteredEmployees.length === 0}
                    >
                        <Printer className="h-4 w-4 mr-2" /> Imprimir
                    </Button>
                </div>
            </CardHeader>
            <CardContent>
                <div className="rounded-md border border-slate-200 dark:border-slate-800 bg-background/50 overflow-x-auto overflow-y-hidden">
                    <Table className="min-w-[800px]">
                        <TableHeader className="bg-muted/50">
                            <TableRow>
                                <TableHead className="w-[200px]">Funcionario</TableHead>
                                <TableHead>C├®dula</TableHead>
                                <TableHead>Cargo</TableHead>
                                <TableHead>Dpto.</TableHead>
                                <TableHead>Ingreso</TableHead>
                                <TableHead>Estado</TableHead>
                                <TableHead className="text-right">Acciones</TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {isLoading ? (
                                <TableRow>
                                    <TableCell colSpan={7} className="text-center h-24 text-muted-foreground">
                                        Cargando informaci├│n...
                                    </TableCell>
                                </TableRow>
                            ) : filteredEmployees.length === 0 ? (
                                <TableRow>
                                    <TableCell colSpan={7} className="text-center h-24 text-muted-foreground">
                                        No se encontraron funcionarios.
                                    </TableCell>
                                </TableRow>
                            ) : (
                                filteredEmployees.map((emp /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */) => (
                                    <TableRow key={emp.id} className="group hover:bg-muted/30 transition-colors">
                                        <TableCell>
                                            <div className="font-medium">{emp.profiles?.nombre} {emp.profiles?.apellido}</div>
                                            <div className="text-xs text-muted-foreground">{emp.profiles?.email}</div>
                                        </TableCell>
                                        <TableCell className="text-muted-foreground">{emp.cedula}</TableCell>
                                        <TableCell>{emp.cargo}</TableCell>
                                        <TableCell>
                                            <span className="text-xs bg-secondary/20 text-secondary-foreground px-2 py-1 rounded-md border border-secondary/30">
                                                {emp.departamentos?.nombre || 'N/A'}
                                            </span>
                                        </TableCell>
                                        <TableCell className="text-muted-foreground text-sm">
                                            {dateFormatter.format(new Date(emp.fecha_ingreso))}
                                        </TableCell>
                                        <TableCell>
                                            <span className={`inline-flex items-center rounded-full px-2.5 py-0.5 text-xs font-semibold ${emp.estado === 'activo' ? 'bg-emerald-100 text-emerald-800 border border-emerald-200 dark:bg-emerald-900/30 dark:text-emerald-400 dark:border-emerald-800' :
                                                emp.estado === 'inactivo' ? 'bg-slate-100 text-slate-800 border border-slate-200 dark:bg-slate-800 dark:text-slate-300 dark:border-slate-700' :
                                                    emp.estado === 'vacaciones' ? 'bg-amber-100 text-amber-800 border border-amber-200 dark:bg-amber-900/30 dark:text-amber-400 dark:border-amber-800' :
                                                        'bg-blue-100 text-blue-800 border border-blue-200 dark:bg-blue-900/30 dark:text-blue-400 dark:border-blue-800'
                                                }`}>
                                                {emp.estado.charAt(0).toUpperCase() + emp.estado.slice(1)}
                                            </span>
                                        </TableCell>
                                        <TableCell className="text-right whitespace-nowrap">
                                            <Button
                                                variant="ghost"
                                                size="icon"
                                                onClick={() => onCertificaciones(emp)}
                                                className="text-muted-foreground hover:text-cyan-600 opacity-0 group-hover:opacity-100 transition-opacity"
                                                title="Certificaciones M├®dicas"
                                            >
                                                <Stethoscope className="h-4 w-4" />
                                            </Button>
                                            <Button
                                                variant="ghost"
                                                size="icon"
                                                onClick={() => onResetPassword(emp)}
                                                className="text-muted-foreground hover:text-amber-600 opacity-0 group-hover:opacity-100 transition-opacity"
                                                title="Forzar Reseteo de Contrase├▒a"
                                            >
                                                <KeyRound className="h-4 w-4" />
                                            </Button>
                                            <Button
                                                variant="ghost"
                                                size="icon"
                                                onClick={() => onEdit(emp)}
                                                className="text-muted-foreground hover:text-primary opacity-0 group-hover:opacity-100 transition-opacity"
                                                title="Editar Ficha"
                                            >
                                                <Pencil className="h-4 w-4" />
                                            </Button>
                                        </TableCell>
                                    </TableRow>
                                ))
                            )}
                        </TableBody>
                    </Table>
                </div>
            </CardContent>

            <FuncionarioPrintDialog
                open={isPrintDialogOpen}
                onOpenChange={setIsPrintDialogOpen}
                employees={filteredEmployees}
            />
        </Card>
    );
}

