import { useState } from 'react';
import { NavLink } from 'react-router-dom';
import {
    BarChart3,
    Users,
    CalendarClock,
    Clock,
    Briefcase,
    Building2,
    Receipt,
    Settings,
    ChevronLeft,
    ChevronRight,
    Map
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { APP_VERSION, APP_COPYRIGHT, APP_DEVELOPER } from '@/lib/appInfo';
import { Button } from '@/components/ui/button';

import { useAuthStore } from '@/stores/authStore';

export function Sidebar({ forceExpand = false }: { forceExpand?: boolean }) {
    const [collapsed, setCollapsed] = useState(false);
    const role = useAuthStore(s => s.role);

    // If mobile menu forces expansion, ignore collapsed state
    const isCollapsed = forceExpand ? false : collapsed;

    const isManager = role === 'superadmin' || role === 'admin';

    const navigation = [
        { name: 'Dashboard', href: '/', icon: BarChart3 },
        { name: 'Funcionarios', href: '/funcionarios', icon: Users },
        { name: 'Horarios', href: '/horarios', icon: CalendarClock },
        { name: 'Asistencia', href: '/asistencia', icon: Clock },
        { name: 'Servicios', href: '/servicios', icon: Briefcase },
        { name: 'Clientes', href: '/clientes', icon: Building2 },
        ...(isManager ? [
            { name: 'Reportes Gerenciales', href: '/reportes', icon: Receipt },
            { name: 'Horas por Cliente', href: '/facturacion', icon: Receipt },
            { name: 'Horas RRHH', href: '/nomina', icon: Clock },
            { name: 'Configuraci├│n', href: '/configuracion', icon: Settings }
        ] : []),
    ];

    return (
        <div className={cn(
            "relative flex flex-col border-r bg-background transition-all duration-300 h-full",
            isCollapsed ? "w-20" : "w-64"
        )}>
            {/* Brand logo / title */}
            <div className="flex h-16 items-center justify-between px-4 py-4 border-b shrink-0">
                {!isCollapsed && (
                    <img src="/soclean-logo.png" alt="Soclean" className="h-10 max-w-[180px] object-contain drop-shadow-sm" />
                )}
                {isCollapsed && (
                    <span className="text-xl font-extrabold text-primary mx-auto">SC</span>
                )}
            </div>

            {/* Navigation Links */}
            <nav className="flex-1 space-y-1 p-3 overflow-y-auto">
                {navigation.map((item) => {
                    const Icon = item.icon;
                    return (
                        <NavLink
                            key={item.name}
                            to={item.href}
                            className={({ isActive }) =>
                                cn(
                                    "group flex items-center rounded-md px-3 py-2.5 text-sm font-medium transition-all",
                                    isActive
                                        ? "bg-primary text-primary-foreground shadow-md"
                                        : "text-muted-foreground hover:bg-muted hover:text-foreground"
                                )
                            }
                            title={isCollapsed ? item.name : undefined}
                        >
                            <Icon className={cn(
                                "flex-shrink-0",
                                isCollapsed ? "h-6 w-6 mx-auto" : "mr-3 h-5 w-5"
                            )} />
                            {!isCollapsed && <span>{item.name}</span>}
                        </NavLink>
                    );
                })}
            </nav>

            {/* Developer Credit & Version */}
            {!isCollapsed && (
                <div className="px-4 py-3 shrink-0 border-t border-dashed border-muted-foreground/10">
                    <p className="text-[10px] text-muted-foreground/50 text-center leading-tight">
                        Desarrollado por <span className="font-semibold text-muted-foreground/70">{APP_DEVELOPER}</span>
                    </p>
                    <p className="text-[9px] text-muted-foreground/40 text-center mt-1 leading-tight">
                        {APP_COPYRIGHT}
                    </p>
                    <p className="text-[9px] text-muted-foreground/30 text-center mt-0.5">
                        v{APP_VERSION}
                    </p>
                </div>
            )}

            {/* Collapse Toggle */}
            {!forceExpand && (
                <div className="p-4 border-t flex justify-end shrink-0">
                    <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => setCollapsed(!isCollapsed)}
                        className="mx-auto flex w-full justify-center"
                        aria-label={isCollapsed ? "Expandir men├║" : "Colapsar men├║"}
                    >
                        {isCollapsed ? <ChevronRight className="h-5 w-5" /> : <ChevronLeft className="h-5 w-5" />}
                    </Button>
                </div>
            )}
        </div>
    );
}

import { useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog';
import {
    Form,
    FormControl,
    FormField,
    FormItem,
    FormLabel,
    FormMessage,
} from '@/components/ui/form';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import type { ServicioFormData } from '@/lib/validations/servicio';
import { servicioSchema } from '@/lib/validations/servicio';
import { useServicios } from '@/hooks/useServicios';
import { useClientes } from '@/hooks/useClientes';

interface Props {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    servicioToEdit? /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */ | null; // usually Servicio type
}

export function ServicioFormDialog({ open, onOpenChange, servicioToEdit }: Props) {
    const { createServicio, updateServicio } = useServicios();
    const { getClientes } = useClientes();
    const { data: clientes = [] } = getClientes;

    const form = useForm<ServicioFormData>({
        resolver: zodResolver(servicioSchema)  /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */,
        defaultValues: {
            nombre: '',
            cliente_id: '',
            descripcion: '',
            direccion: '',
            estado: 'activo',
        },
    });

    useEffect(() => {
        if (servicioToEdit) {
            form.reset({
                id: servicioToEdit.id,
                nombre: servicioToEdit.nombre || '',
                cliente_id: servicioToEdit.cliente_id || '',
                descripcion: servicioToEdit.descripcion || '',
                direccion: servicioToEdit.direccion || '',
                estado: servicioToEdit.estado  /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */ || 'activo',
            });
        } else {
            form.reset({
                nombre: '',
                cliente_id: '',
                descripcion: '',
                direccion: '',
                estado: 'activo',
            });
        }
    }, [servicioToEdit, form, open]);

    const onSubmit = async (data: ServicioFormData) => {
        const isEditing = !!servicioToEdit;
        const loadingId = toast.loading(isEditing ? 'Actualizando servicio...' : 'Registrando nuevo servicio...');

        try {
            if (isEditing) {
                await updateServicio.mutateAsync({ id: servicioToEdit!.id, data });
                toast.dismiss(loadingId);
                toast.success('Servicio actualizado correctamente');
            } else {
                await createServicio.mutateAsync(data);
                toast.dismiss(loadingId);
                toast.success('Servicio registrado exitosamente en el cliente');
            }
            onOpenChange(false);
        } catch (error /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */) {
            console.error("Form Submit Error:", error);
            toast.dismiss(loadingId);
            toast.error(`Error al revisar datos: ${error.message || 'No se pudo guardar la informaci├│n'}`, { duration: 8000 });
        }
    };

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="sm:max-w-[700px] max-h-[90vh] overflow-y-auto">
                <DialogHeader>
                    <DialogTitle>{servicioToEdit ? 'Editar Servicio / Contrato' : 'A├▒adir Nuevo Servicio a Cliente'}</DialogTitle>
                </DialogHeader>

                <Form {...form}>
                    <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
                        <div className="grid grid-cols-2 gap-4">

                            <div className="space-y-2 col-span-2">
                                <h3 className="font-semibold border-b pb-2">Datos Principales</h3>
                            </div>

                            <FormField
                                control={form.control}
                                name="cliente_id"
                                render={({ field }) => (
                                    <FormItem className="col-span-2">
                                        <FormLabel>Cliente Asignado (Obligatorio)</FormLabel>
                                        <Select onValueChange={field.onChange} value={field.value || undefined}>
                                            <FormControl>
                                                <SelectTrigger>
                                                    <SelectValue placeholder="Seleccionar el cliente a quien pertenece" />
                                                </SelectTrigger>
                                            </FormControl>
                                            <SelectContent>
                                                {clientes.map(cli => (
                                                    <SelectItem key={cli.id} value={cli.id}>
                                                        {cli.razon_social} {cli.nombre_fantasia ? `(${cli.nombre_fantasia})` : ''} - RUT: {cli.rut}
                                                    </SelectItem>
                                                ))}
                                                {clientes.length === 0 && (
                                                    <SelectItem value="none" disabled>No se encontraron clientes activos</SelectItem>
                                                )}
                                            </SelectContent>
                                        </Select>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <FormField
                                control={form.control}
                                name="nombre"
                                render={({ field }) => (
                                    <FormItem className="col-span-2 sm:col-span-1">
                                        <FormLabel>Nombre del Servicio</FormLabel>
                                        <FormControl>
                                            <Input placeholder="Ej. Limpieza Oficina Carrasco" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <FormField
                                control={form.control}
                                name="estado"
                                render={({ field }) => (
                                    <FormItem className="col-span-2 sm:col-span-1">
                                        <FormLabel>Estado Operativo</FormLabel>
                                        <Select onValueChange={field.onChange} defaultValue={field.value}>
                                            <FormControl>
                                                <SelectTrigger>
                                                    <SelectValue placeholder="Seleccionar estado" />
                                                </SelectTrigger>
                                            </FormControl>
                                            <SelectContent>
                                                <SelectItem value="activo">Activo</SelectItem>
                                                <SelectItem value="inactivo">Inactivo / Pausado</SelectItem>
                                            </SelectContent>
                                        </Select>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <FormField
                                control={form.control}
                                name="direccion"
                                render={({ field }) => (
                                    <FormItem className="col-span-2">
                                        <FormLabel>Direcci├│n F├¡sica del Servicio (Visible para funcionarios)</FormLabel>
                                        <FormControl>
                                            <Input placeholder="Ej. Arocena 1234, Local 02" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <FormField
                                control={form.control}
                                name="descripcion"
                                render={({ field }) => (
                                    <FormItem className="col-span-2">
                                        <FormLabel>Instrucciones o Detalles Extra (Opcional)</FormLabel>
                                        <FormControl>
                                            <Textarea placeholder="Ej. Llaves en porter├¡a, llevar maquinaria especial..." {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                        </div>

                        <div className="flex justify-end pt-6 border-t mt-4 gap-2">
                            <Button type="button" variant="outline" onClick={() => onOpenChange(false)}>
                                Cancelar
                            </Button>
                            <Button type="submit">
                                {servicioToEdit ? 'Guardar Cambios' : 'A├▒adir Servicio a Cliente'}
                            </Button>
                        </div>
                    </form>
                </Form>
            </DialogContent>
        </Dialog>
    );
}

