        googleMapsApiKey: import.meta.env.VITE_GOOGLE_MAPS_API_KEY || '',
        libraries: LIBRARIES,
    });

    const selectedService = servicios.find(s => s.id === selectedServiceId);
    const selectedFuncionario = funcionarios.find(f => f.id === selectedFuncionarioId);

    const activeServices = useMemo(() => servicios.filter(s => s.estado === 'activo'), [servicios]);
    const activeFuncionarios = useMemo(() => funcionarios.filter(f => f.estado === 'activo'), [funcionarios]);

    const [hasAttemptedGeocode, setHasAttemptedGeocode] = useState(false);

    // Geocode active services to place green markers on the map
    useEffect(() => {
        if (!isLoaded || activeServices.length === 0 || serviceMarkers.length > 0 || hasAttemptedGeocode) return;
        
        setHasAttemptedGeocode(true); // Prevent re-runs if it fails or returns empty
        
        const geocoder = new window.google.maps.Geocoder();
        const fetchGeocodes = async () => {
            const newMarkers /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */[] = [];
            for (const s of activeServices) {
                try {
                    const res = await geocoder.geocode({ address: `${s.direccion}, Montevideo, Uruguay` });
                    if (res.results && res.results[0]) {
                        newMarkers.push({
                            id: s.id,
                            title: `${s.clientes?.razon_social || ''} - ${s.nombre}`,
                            lat: res.results[0].geometry.location.lat(),
                            lng: res.results[0].geometry.location.lng()
                        });
                    }
                } catch (error) {
                    console.log(`Geocoding error for ${s.direccion}`, error);
                }
            }
            if (newMarkers.length > 0) {
                setServiceMarkers(newMarkers);
            }
        };
        fetchGeocodes();
    }, [isLoaded, activeServices, serviceMarkers.length, hasAttemptedGeocode]);

    const handleGenerateRoute = async () => {
        if (!selectedService || !selectedFuncionario || !isLoaded) return;
        
        const google = window.google;
        const directionsService = new google.maps.DirectionsService();

        try {
            const results = await directionsService.route({
                origin: `${selectedFuncionario.direccion}, Montevideo, Uruguay`,
                destination: `${selectedService.direccion}, Montevideo, Uruguay`,
                travelMode: google.maps.TravelMode[directionsMode] || google.maps.TravelMode.TRANSIT,
            });
            setDirectionsResponse(results);
            if (results.routes[0]?.legs[0]) {
                setDistance(results.routes[0].legs[0].distance?.text || '');
                setDuration(results.routes[0].legs[0].duration?.text || '');
            }
        } catch (error) {
            console.error("Error al calcular ruta:", error);
        }
    };

    const handleOpenExternalRoute = () => {
        if (!selectedService || !selectedFuncionario) return;
        const origin = encodeURIComponent(`${selectedFuncionario.direccion}, Montevideo`);
        const destination = encodeURIComponent(`${selectedService.direccion}, Montevideo`);
        // Open google maps directions specifying transit (buses) to show full transit options
        window.open(`https://www.google.com/maps/dir/?api=1&origin=${origin}&destination=${destination}&travelmode=transit`, '_blank');
    };

    return (
        <div className="space-y-6 animate-in fade-in duration-500 max-w-7xl mx-auto">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div>
                    <h2 className="text-3xl font-bold tracking-tight text-primary flex items-center gap-2">
                        <Map className="h-8 w-8" />
                        Log├¡stica y Rutas
                    </h2>
                    <p className="text-muted-foreground text-sm mt-1">Asigna funcionarios a locaciones y as├¡stelos en su trayecto hacia cada servicio.</p>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* Left Panel - Selection Controls */}
                <div className="space-y-6">
                    <Card className="border-slate-200 dark:border-slate-800 bg-white/60 dark:bg-slate-900/60 backdrop-blur-md shadow-sm">
                        <CardHeader>
                            <CardTitle className="text-lg flex items-center gap-2">
                                <MapPin className="h-5 w-5 text-coreops-primary" />
                                1. Seleccionar Servicio
                            </CardTitle>
                            <CardDescription>Escoge el servicio al que deseas enviar personal</CardDescription>
                        </CardHeader>
                        <CardContent>
                            <Select value={selectedServiceId} onValueChange={setSelectedServiceId}>
                                <SelectTrigger className="w-full">
                                    <SelectValue placeholder="Elige un servicio..." />
                                </SelectTrigger>
                                <SelectContent>
                                    {activeServices.length === 0 && <SelectItem value="none" disabled>No hay servicios activos</SelectItem>}
                                    {activeServices.map(s => (
                                        <SelectItem key={s.id} value={s.id}>
                                            {s.clientes?.razon_social} - {s.nombre}
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>

                            {selectedService && (
                                <div className="mt-4 p-3 bg-muted/50 rounded-lg text-sm">
                                    <p className="font-semibold">{selectedService.clientes?.razon_social}</p>
                                    <p className="text-muted-foreground break-words">{selectedService.direccion}</p>
                                </div>
                            )}
                        </CardContent>
                    </Card>

                    <Card className="border-slate-200 dark:border-slate-800 bg-white/60 dark:bg-slate-900/60 backdrop-blur-md shadow-sm">
                        <CardHeader>
                            <CardTitle className="text-lg flex items-center gap-2">
                                <User className="h-5 w-5 text-blue-500" />
                                2. Elegir Funcionario
                            </CardTitle>
                            <CardDescription>Identifica desde d├│nde parte el empleado</CardDescription>
                        </CardHeader>
                        <CardContent>
                            <Select value={selectedFuncionarioId} onValueChange={setSelectedFuncionarioId}>
                                <SelectTrigger className="w-full">
                                    <SelectValue placeholder="Elige un funcionario..." />
                                </SelectTrigger>
                                <SelectContent>
                                    {activeFuncionarios.length === 0 && <SelectItem value="none" disabled>No hay funcionarios activos</SelectItem>}
                                    {activeFuncionarios.map(f => (
                                        <SelectItem key={f.id} value={f.id}>
                                            {f.profiles?.nombre} {f.profiles?.apellido} - {f.cargo}
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>

                            {selectedFuncionario && (
                                <div className="mt-4 p-3 bg-muted/50 rounded-lg text-sm">
                                    <p className="font-semibold">{selectedFuncionario.profiles?.nombre} {selectedFuncionario.profiles?.apellido}</p>
                                    <p className="text-muted-foreground break-words">{selectedFuncionario.direccion}</p>
                                </div>
                            )}
                        </CardContent>
                    </Card>

                    <Button
                        className="w-full h-12 text-md shadow-lg"
                        disabled={!selectedService || !selectedFuncionario}
                        onClick={handleGenerateRoute}
                    >
                        Generar Mapeo
                    </Button>
                </div>

                {/* Right Panel - Map Display */}
                <div className="lg:col-span-2">
                    <Card className="border-slate-200 dark:border-slate-800 bg-white/60 dark:bg-slate-900/60 backdrop-blur-md shadow-sm h-[600px] flex flex-col">
                        <CardContent className="p-2 flex-grow relative overflow-hidden h-full rounded-b-lg">
                            {!isLoaded ? (
                                <div className="h-full w-full flex flex-col items-center justify-center text-muted-foreground p-12 text-center bg-slate-50 dark:bg-slate-900/50 rounded-lg">
                                    {loadError ? (
                                        <>
                                            <Map className="h-16 w-16 mb-4 text-red-500 opacity-50" />
                                            <h3 className="text-xl font-semibold mb-2">Error de Google Maps</h3>
                                            <p className="max-w-sm">No se pudo cargar la API Key. Configura <code>VITE_GOOGLE_MAPS_API_KEY</code> en tu Vercel / .env</p>
                                        </>
                                    ) : (
                                        <>
                                            <Loader2 className="h-16 w-16 mb-4 opacity-50 animate-spin" />
                                            <h3 className="text-xl font-semibold mb-2">Cargando Mapas...</h3>
                                        </>
                                    )}
                                </div>
                            ) : directionsResponse ? (
                                <div className="h-full w-full relative">
                                    <GoogleMap
                                        center={MVD_CENTER}
                                        zoom={12}
                                        mapContainerStyle={{ width: '100%', height: '100%', borderRadius: '0.5rem' }}
                                        options={{
                                            zoomControl: true,
                                            streetViewControl: false,
                                            mapTypeControl: false,
                                            fullscreenControl: true,
                                        }}
                                    >
                                        <DirectionsRenderer
                                            directions={directionsResponse}
                                            options={{
                                                polylineOptions: { strokeColor: '#10b981', strokeWeight: 5 }
                                            }}
                                        />
                                        {serviceMarkers.map(m => (
                                            <Marker 
                                                key={m.id} 
                                                position={{lat: m.lat, lng: m.lng}} 
                                                title={m.title}
                                                icon="http://maps.google.com/mapfiles/ms/icons/green-dot.png" 
                                            />
                                        ))}
                                    </GoogleMap>

                                    {/* Overlay Helper */}
                                    <div className="absolute top-4 right-4 bg-white/95 dark:bg-slate-900/95 p-4 rounded-xl shadow-2xl border border-slate-200 dark:border-slate-700 w-72 backdrop-blur-md animate-in fade-in slide-in-from-right-4">
                                        <h4 className="font-bold flex items-center gap-2 text-slate-900 dark:text-white mb-2">
                                            <Navigation className="h-4 w-4 text-emerald-500" />
                                            Informaci├│n de Ruta
                                        </h4>
                                        <div className="space-y-2 mb-4">
                                            <p className="text-sm font-semibold flex justify-between">
                                                <span className="text-slate-500">Distancia:</span> 
                                                <span>{distance}</span>
                                            </p>
                                            <p className="text-sm font-semibold flex justify-between">
                                                <span className="text-slate-500">Tiempo estimado:</span> 
                                                <span className="text-emerald-600 dark:text-emerald-400">{duration}</span>
                                            </p>
                                        </div>
                                        <div className="flex gap-2 mt-3">
                                            <Button
                                                size="sm"
                                                variant={directionsMode === 'TRANSIT' ? 'default' : 'outline'}
                                                onClick={() => { setDirectionsMode('TRANSIT'); handleGenerateRoute(); }}
                                                className={`flex-1 ${directionsMode === 'TRANSIT' ? 'bg-emerald-600 hover:bg-emerald-700 text-white' : ''}`}
                                            >
                                                ├ômnibus
                                            </Button>
                                            <Button
                                                size="sm"
                                                variant={directionsMode === 'DRIVING' ? 'default' : 'outline'}
                                                onClick={() => { setDirectionsMode('DRIVING'); handleGenerateRoute(); }}
                                                className={`flex-1 ${directionsMode === 'DRIVING' ? 'bg-coreops-primary text-white' : ''}`}
                                            >
                                                Auto
                                            </Button>
                                        </div>
                                        <Button
                                            size="sm"
                                            variant="secondary"
                                            onClick={handleOpenExternalRoute}
                                            className="w-full mt-3 font-semibold"
                                        >
                                            Comparar todos los ├ômnibus
                                        </Button>
                                    </div>
                                </div>
                            ) : (
                                <div className="h-full w-full flex flex-col items-center justify-center text-muted-foreground p-12 text-center bg-slate-50 dark:bg-slate-900/50 rounded-lg">
                                    <GoogleMap
                                        center={MVD_CENTER}
                                        zoom={12}
                                        mapContainerStyle={{ width: '100%', height: '100%', position: 'absolute', top: 0, left: 0, zIndex: 0 }}
                                        options={{ disableDefaultUI: true }}
                                    >
                                        {serviceMarkers.map(m => (
                                            <Marker 
                                                key={m.id} 
                                                position={{lat: m.lat, lng: m.lng}} 
                                                title={m.title}
                                                icon="http://maps.google.com/mapfiles/ms/icons/green-dot.png" 
                                            />
                                        ))}
                                    </GoogleMap>
                                    <div className="z-10 bg-white/90 dark:bg-slate-900/90 p-6 rounded-2xl shadow-xl backdrop-blur-md">
                                        <Map className="h-16 w-16 mb-4 opacity-40 mx-auto" />
                                        <h3 className="text-xl font-semibold mb-2">Visualizador Operativo</h3>
                                        <p className="max-w-sm text-sm">
                                            Selecciona un servicio y el funcionario designado en el panel lateral para calcular la mejor ruta.
                                        </p>
                                    </div>
                                </div>
                            )}
                        </CardContent>
                    </Card>
                </div>
            </div>
        </div>
    );
}

import { useState, useMemo } from 'react';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { FileText, Download, Calendar, ArrowRightCircle, Filter } from 'lucide-react';
import { useAsistencia } from '@/hooks/useAsistencia';
import { toast } from 'sonner';
import * as XLSX from 'xlsx';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';

export default function Reports() {
    const [desde, setDesde] = useState<string>(new Date().toISOString().substring(0, 8) + '01');
    const [hasta, setHasta] = useState<string>(new Date().toISOString().substring(0, 10));
    const [loadingReport, setLoadingReport] = useState(false);
    const [filtroFuncionario, setFiltroFuncionario] = useState<string>('todos');
    const [filtroServicio, setFiltroServicio] = useState<string>('todos');

    // Pass date filters to avoid massive overfetching
    const { getAsistencias } = useAsistencia(desde, hasta);
    const { data: asistencias = [], isLoading } = getAsistencias;

    // Obtener listas ├║nicas con map y useMemo para evitar loops O(N^2) que congelan la UI
    const uniqueEmpleados = useMemo(() => {
        const map = new Map();
        asistencias.forEach((current /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */) => {
            if (current.funcionario_id && !map.has(current.funcionario_id)) {
                map.set(current.funcionario_id, current);
            }
        });
        return Array.from(map.values()).sort((a /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */, b /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */) => {
            const nameA = a.funcionarios?.profiles?.nombre || '';
            const nameB = b.funcionarios?.profiles?.nombre || '';
            return nameA.localeCompare(nameB);
        });
    }, [asistencias]);

    const uniqueServicios = useMemo(() => {
        const map = new Map();
        asistencias.forEach((current /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */) => {
            const servicioId = current.horarios?.servicio_id;
            if (servicioId && !map.has(servicioId)) {
                map.set(servicioId, current);
            }
        });
        return Array.from(map.values()).sort((a /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */, b /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */) => {
            const nameA = a.horarios?.servicios?.nombre || '';
            const nameB = b.horarios?.servicios?.nombre || '';
            return nameA.localeCompare(nameB);
        });
    }, [asistencias]);

    const generarReporteCSV = (tipo: 'empleados' | 'clientes' | 'quincena1') => {
        setLoadingReport(true);
        toast.info(`Generando reporte de ${tipo}...`);

        setTimeout(() => {
            // Filtrar asistencias por rango de fechas
            const registrosRango = asistencias.filter((a /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */) => {
                 return a.fecha >= desde && a.fecha <= hasta;
            });

            let registrosAUsar = registrosRango;

            // Aplicar filtros adicionales si est├ín seleccionados
            if (filtroFuncionario !== 'todos') {
                registrosAUsar = registrosAUsar.filter((a /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */) => a.funcionario_id === filtroFuncionario);
            }
            if (filtroServicio !== 'todos') {
                registrosAUsar = registrosAUsar.filter((a /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */) => a.horarios?.servicio_id === filtroServicio);
            }

            if (tipo === 'quincena1') {
                registrosAUsar = registrosAUsar.filter(a => parseInt(a.fecha.split('-')[2]) <= 15);
            }

            if (registrosAUsar.length === 0) {
                toast.error('No hay datos registrados en el per├¡odo seleccionado para exportar.');
                setLoadingReport(false);
                return;
            }

            // Agrupar datos seg├║n el tipo
            let dataToExport /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */[] = [];
            if (tipo === 'empleados' || tipo === 'quincena1') {
                // Ordenar por empleado alfab├®ticamente, y luego por fecha
                const registrosOrdenados = [...registrosAUsar].sort((a, b) => {
                    const nameA = a.funcionarios?.profiles?.nombre || '';
                    const nameB = b.funcionarios?.profiles?.nombre || '';
                    if (nameA !== nameB) return nameA.localeCompare(nameB);
                    return a.fecha.localeCompare(b.fecha);
                });

                dataToExport = registrosOrdenados.map(r => {
                    let totalHoras = '0 hs';
                    const hEntrada = r.horarios?.hora_entrada?.substring(0, 5);
                    const hSalida = r.horarios?.hora_salida?.substring(0, 5);

                    if (hEntrada && hSalida) {
                        const [eH, eM] = hEntrada.split(':').map(Number);
                        const [sH, sM] = hSalida.split(':').map(Number);
                        let minutes = (sH * 60 + sM) - (eH * 60 + eM);
                        if (minutes < 0) minutes += 24 * 60; // manejo de turnos de noche

                        const hours = Math.floor(minutes / 60);
                        const mins = minutes % 60;
                        totalHoras = mins === 0 ? `${hours} hs` : `${hours}:${mins.toString().padStart(2, '0')} hs`;
                    }

                    return {
                        'Nombre Empleado': `${r.funcionarios?.profiles?.nombre} ${r.funcionarios?.profiles?.apellido}`,
                        'Fecha': r.fecha,
                        'C├®dula': r.funcionarios?.cedula || 'N/A',
                        'Cliente / Servicio': `${r.horarios?.servicios?.clientes?.razon_social || ''} - ${r.horarios?.servicios?.nombre || ''}`,
                        'Horario de Entrada': hEntrada || 'N/A',
                        'Horario de Salida': hSalida || 'N/A',
                        'Total Horas': totalHoras,
                        'Estado Confirmaci├│n': r.estado.toUpperCase(),
                        'Observaciones': r.observaciones || ''
                    };
                });
            } else if (tipo === 'clientes') {
                // Ordenar por Cliente, luego por Servicio, y luego por Fecha
                const registrosOrdenados = [...registrosAUsar].sort((a, b) => {
                    const clientA = a.horarios?.servicios?.clientes?.razon_social || '';
                    const clientB = b.horarios?.servicios?.clientes?.razon_social || '';
                    if (clientA !== clientB) return clientA.localeCompare(clientB);

                    const servA = a.horarios?.servicios?.nombre || '';
                    const servB = b.horarios?.servicios?.nombre || '';
                    if (servA !== servB) return servA.localeCompare(servB);

                    return a.fecha.localeCompare(b.fecha);
                });

                dataToExport = registrosOrdenados.map(r => {
                    let totalHoras = '0 hs';
                    const hEntrada = r.horarios?.hora_entrada?.substring(0, 5);
                    const hSalida = r.horarios?.hora_salida?.substring(0, 5);

                    if (hEntrada && hSalida) {
                        const [eH, eM] = hEntrada.split(':').map(Number);
                        const [sH, sM] = hSalida.split(':').map(Number);
                        let minutes = (sH * 60 + sM) - (eH * 60 + eM);
                        if (minutes < 0) minutes += 24 * 60; // manejo de turnos de noche

                        const hours = Math.floor(minutes / 60);
                        const mins = minutes % 60;
                        totalHoras = mins === 0 ? `${hours} hs` : `${hours}:${mins.toString().padStart(2, '0')} hs`;
                    }

                    return {
                        'Cliente': r.horarios?.servicios?.clientes?.razon_social || 'N/A',
                        'Servicio': r.horarios?.servicios?.nombre || 'N/A',
                        'Fecha': r.fecha,
                        'Nombre Empleado': `${r.funcionarios?.profiles?.nombre} ${r.funcionarios?.profiles?.apellido}`,
                        'Horario de Entrada': hEntrada || 'N/A',
                        'Horario de Salida': hSalida || 'N/A',
                        'Total Horas': totalHoras,
                        'Estado': r.estado.toUpperCase(),
                        'Observaciones': r.observaciones || ''
                    };
                });
            }

            // Calcular el total global de tiempo en todos los registros mostrados
            let totalMinutosGlobal = 0;
            dataToExport.forEach(row => {
                if (row['Total Horas'] && row['Total Horas'] !== '0 hs') {
                    const timePart = row['Total Horas'].replace(' hs', '').trim();
                    const parts = timePart.split(':');
                    if (parts.length === 2) {
                        totalMinutosGlobal += (parseInt(parts[0]) * 60) + parseInt(parts[1]);
                    } else if (parts.length === 1) {
                        totalMinutosGlobal += parseInt(parts[0]) * 60;
                    }
                }
            });

            if (totalMinutosGlobal > 0) {
                const totalHoursCalculated = Math.floor(totalMinutosGlobal / 60);
                const totalMinsCalculated = totalMinutosGlobal % 60;
                const formattedGlobalTotal = totalMinsCalculated === 0
                    ? `${totalHoursCalculated} hs`
                    : `${totalHoursCalculated}:${totalMinsCalculated.toString().padStart(2, '0')} hs`;

                // Agregar una fila en blanco separadora
                dataToExport.push({});

                // Crear objeto de total. Mapear "Total Horas" a la columna respectiva, 
                // y usar la primera columna disponible para el texto "TOTAL GLOBAL DE HORAS DE ESTE REPORTE"
                const summaryRow /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */ = {};
                const firstKey = Object.keys(dataToExport[0])[0]; // 'Nombre Empleado' o 'Cliente'
                summaryRow[firstKey] = '=> TOTAL GLOBAL DE HORAS DE ESTE REPORTE <=';
                summaryRow['Total Horas'] = formattedGlobalTotal;

                // Si el reporte es 'empleados', 'Total Horas' se llamaba diferente. Lo unificamos.
                if (tipo !== 'clientes') {
                    summaryRow['Total Horas Te├│ricas'] = formattedGlobalTotal;
                    delete summaryRow['Total Horas'];
                }

                dataToExport.push(summaryRow);
            }

            // Generar y descargar archivo Excel
            const worksheet = XLSX.utils.json_to_sheet(dataToExport);
            const workbook = XLSX.utils.book_new();
            XLSX.utils.book_append_sheet(workbook, worksheet, "Reporte");
            XLSX.writeFile(workbook, `reporte_soclean_${tipo}_${desde}_al_${hasta}.xlsx`);

            toast.success('Reporte exportado exitosamente con ruta de auditor├¡a adjunta');
            setLoadingReport(false);
        }, 1200);
    };

    return (
        <div className="space-y-6 animate-in fade-in duration-500">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div>
                    <h2 className="text-3xl font-bold tracking-tight text-primary flex items-center gap-2">
                        <FileText className="h-8 w-8 text-coreops-primary" />
                        Reportes Gerenciales y de Operaciones
                    </h2>
                    <p className="text-muted-foreground text-sm mt-1">Generaci├│n de archivos para Recursos Humanos, Administraci├│n y Alta Direcci├│n.</p>
                </div>
            </div>

            <Card className="border-slate-200 dark:border-slate-800 bg-white/60 dark:bg-slate-900/60 shadow-sm">
                <CardHeader className="border-b bg-slate-50 dark:bg-slate-900/50">
                    <CardTitle className="text-lg flex items-center gap-2">
                        <Calendar className="h-5 w-5 text-slate-500" />
                        Selecci├│n de Per├¡odo a Exportar
                    </CardTitle>
                </CardHeader>
                <CardContent className="pt-6">
                    <div className="flex flex-col md:flex-row gap-4 mb-8">
                        <div className="w-full md:w-48 space-y-2">
                            <label className="text-sm font-semibold text-slate-700">Fecha Desde</label>
                            <input
                                type="date"
                                value={desde}
                                onChange={(e) => setDesde(e.target.value)}
                                className="flex h-10 w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm text-slate-900 focus:outline-none focus:ring-2 focus:ring-coreops-primary"
                            />
                        </div>
                        <div className="w-full md:w-48 space-y-2">
                            <label className="text-sm font-semibold text-slate-700">Fecha Hasta</label>
                            <input
                                type="date"
                                value={hasta}
                                onChange={(e) => setHasta(e.target.value)}
                                className="flex h-10 w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm text-slate-900 focus:outline-none focus:ring-2 focus:ring-coreops-primary"
                            />
                        </div>

                        <div className="w-full md:w-64 space-y-2">
                            <label className="text-sm font-semibold text-slate-700 flex items-center gap-1">
                                <Filter className="h-3 w-3" />
                                Filtrar por Funcionario
                            </label>
                            <Select value={filtroFuncionario} onValueChange={setFiltroFuncionario}>
                                <SelectTrigger className="h-10 border-slate-300">
                                    <SelectValue placeholder="Todos los funcionarios" />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="todos">Todos los Empleados</SelectItem>
                                    {uniqueEmpleados.map((a /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */) => (
                                        <SelectItem key={`emp_${a.funcionario_id}`} value={a.funcionario_id}>
                                            {a.funcionarios?.profiles?.nombre} {a.funcionarios?.profiles?.apellido}
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>

                        <div className="w-full md:w-72 space-y-2">
                            <label className="text-sm font-semibold text-slate-700 flex items-center gap-1">
                                <Filter className="h-3 w-3" />
                                Filtrar por Servicio
                            </label>
                            <Select value={filtroServicio} onValueChange={setFiltroServicio}>
                                <SelectTrigger className="h-10 border-slate-300">
                                    <SelectValue placeholder="Todos los servicios" />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="todos">Todos los Servicios</SelectItem>
                                    {uniqueServicios.map((a /* Justificaci├│n: Tipo din├ímico pendiente de tipado estricto */) => (
                                        <SelectItem key={`srv_${a.horarios?.servicio_id}`} value={a.horarios?.servicio_id}>
                                            {a.horarios?.servicios?.clientes?.razon_social} - {a.horarios?.servicios?.nombre}
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">

                        {/* Reporte RRHH (1) */}
                        <div className="p-5 border border-slate-200 dark:border-slate-800 rounded-xl bg-white hover:border-coreops-primary transition-colors flex flex-col h-full shadow-sm">
                            <h3 className="font-bold text-lg mb-2 text-slate-800">Cierre 1ra Quincena (RRHH)</h3>
                            <p className="text-sm text-slate-500 mb-6 flex-grow">Archivo detallado de la primer quincena para adelantos de n├│mina. Para enviar el d├¡a 16 de cada mes.</p>
                            <Button
                                className="w-full bg-slate-800 hover:bg-slate-700"
                                onClick={() => generarReporteCSV('quincena1')}
                                disabled={loadingReport || isLoading}
                            >
                                <Download className="h-4 w-4 mr-2" />
                                Exportar Quincena a Excel
                            </Button>
                        </div>

                        {/* Reporte RRHH (2) */}
                        <div className="p-5 border border-slate-200 dark:border-slate-800 rounded-xl bg-white hover:border-coreops-primary transition-colors flex flex-col h-full shadow-sm">
                            <h3 className="font-bold text-lg mb-2 text-slate-800">N├│mina Mensual Empleados</h3>
                            <p className="text-sm text-slate-500 mb-6 flex-grow">Horas reales trabajadas d├¡a por d├¡a por cada empleado. Para enviar el d├¡a 1 de cada mes al departamento de liquidaci├│n.</p>
                            <Button
                                className="w-full bg-coreops-primary hover:bg-coreops-secondary"
                                onClick={() => generarReporteCSV('empleados')}
                                disabled={loadingReport || isLoading}
                            >
                                <Download className="h-4 w-4 mr-2" />
                                Exportar Mes a Excel
                            </Button>
                        </div>

                        {/* Reporte Administraci├│n (3) */}
                        <div className="p-5 border border-slate-200 dark:border-slate-800 rounded-xl bg-blue-50/50 hover:border-blue-300 transition-colors flex flex-col h-full shadow-sm">
                            <h3 className="font-bold text-lg mb-2 text-blue-900">Control Servicios a Clientes</h3>
                            <p className="text-sm text-slate-600 mb-6 flex-grow">Reporte de horas trabajadas y servicios ca├¡dos diferenciado por cliente. Ideal para el departamento de Facturaci├│n (d├¡a 1).</p>
                            <Button
                                variant="outline"
                                className="w-full border-blue-500 text-blue-700 hover:bg-blue-50"
                                onClick={() => generarReporteCSV('clientes')}
                                disabled={loadingReport || isLoading}
                            >
                                <ArrowRightCircle className="h-4 w-4 mr-2" />
                                Exportar a Administraci├│n
                            </Button>
                        </div>

                    </div>
                </CardContent>
            </Card>

            <div className="bg-slate-100 p-4 border border-slate-200 text-sm text-slate-500 rounded-xl flex items-start gap-4">
                <div className="p-2 bg-white rounded-lg inline-flex">
                    <FileText className="h-5 w-5 text-slate-400" />
                </div>
                <div>
                    <strong className="block text-slate-700 mb-1">Registro de Auditor├¡a Interna Activo</strong>
                    Todos los reportes incluyen digitalmente los logs inmutables que registran qui├®n (usuario), a qu├® hora,
                    y qu├® registros edit├│ a lo largo del mes en el sistema operativo central garantizando 100% de trazabilidad para la Direcci├│n y Jefatura.
                </div>
            </div>
        </div>
    );
}
